pages.css:
.page-cover {
  box-sizing: border-box;
  width: 1242px;
  height: 1660px;
  background-color: #F7F7F8;
  background-image: 
    linear-gradient(rgba(26,26,26,0.04) 2px, transparent 2px),
    linear-gradient(90deg, rgba(26,26,26,0.04) 2px, transparent 2px);
  background-size: 48px 48px;
  background-position: -2px -2px;
  border: 20px solid #1A1A1A;
  padding: 88px 96px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
}

.page-header {
  display: inline-flex;
  align-items: center;
  align-self: flex-start;
  gap: 16px;
  background-color: #1A1A1A;
  padding: 12px 28px 12px 20px;
  border-radius: 100px;
}

.header-icon {
  font-size: 40px;
}

.header-label {
  font-size: 36px;
  font-weight: 700;
  color: #FFFFFF;
  letter-spacing: 0;
}

.cover-title {
  display: flex;
  flex-direction: column;
  gap: 20px;
  margin-top: 100px;
  margin-bottom: auto;
}

.title-line {
  font-size: 120px;
  font-weight: 900;
  line-height: 1.2;
  color: #1A1A1A;
  margin: 0;
  letter-spacing: 0;
}

.title-line-2 {
  color: #D92525;
}

.sub-items {
  display: flex;
  flex-direction: column;
  gap: 56px;
  border-top: 6px solid #1A1A1A;
  padding-top: 56px;
  margin-bottom: 24px;
}

.sub-item {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.sub-tag {
  align-self: flex-start;
  font-size: 36px;
  font-weight: 800;
  color: #FFFFFF;
  background-color: #D92525;
  padding: 10px 20px;
  border-radius: 8px;
  letter-spacing: 0;
}

.sub-text {
  font-size: 42px;
  line-height: 1.6;
  color: #222222;
  margin: 0;
  font-weight: 500;
  letter-spacing: 0;
}

.page-02 {
  width: 1242px;
  height: 1660px;
  background-color: #F8F9FA;
  box-sizing: border-box;
  padding: 88px 96px;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  display: flex;
  flex-direction: column;
  color: #111827;
  letter-spacing: 0;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 44px;
}

.header-icon {
  font-size: 40px;
}

.header-label {
  font-size: 36px;
  font-weight: 600;
  color: #6B7280;
}

.page-title {
  display: flex;
  flex-direction: column;
  gap: 16px;
  margin-bottom: 56px;
}

.title-line {
  font-size: 104px;
  font-weight: 800;
  line-height: 1.15;
  color: #111827;
}

.title-highlight {
  color: #DC2626;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.proof-item {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 36px 48px;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.03);
  border: 1px solid #F3F4F6;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.proof-tag {
  align-self: flex-start;
  font-size: 34px;
  font-weight: 700;
  color: #DC2626;
  background-color: #FEF2F2;
  padding: 8px 16px;
  border-radius: 8px;
}

.proof-text {
  font-size: 40px;
  line-height: 1.5;
  color: #374151;
  margin: 0;
  font-weight: 400;
}

.page {
  box-sizing: border-box;
  width: 1242px;
  height: 1660px;
  background-color: #0A0D14;
  color: #FFFFFF;
  padding: 96px 96px 80px 96px;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
  display: flex;
  flex-direction: column;
}

.page-header {
  display: flex;
  align-items: center;
  margin-bottom: 40px;
}

.header-icon {
  font-size: 40px;
  margin-right: 16px;
}

.header-label {
  font-size: 38px;
  font-weight: 600;
  color: #8B95A5;
}

.page-title-section {
  margin-bottom: 48px;
}

.page-title {
  font-size: 96px;
  font-weight: 800;
  line-height: 1.2;
  color: #FFFFFF;
}

.highlight-section {
  margin-bottom: 40px;
  padding-bottom: 40px;
  border-bottom: 2px solid #1A2233;
}

.highlight-value {
  font-size: 112px;
  font-weight: 900;
  color: #00E599;
  line-height: 1.1;
  margin-bottom: 12px;
}

.highlight-sub {
  font-size: 40px;
  color: #8B95A5;
  font-weight: 500;
}

.sub-items-section {
  display: flex;
  flex-direction: column;
  gap: 32px;
  flex: 1;
}

.sub-item {
  display: flex;
  flex-direction: column;
}

.sub-tag {
  display: flex;
  align-items: center;
  font-size: 36px;
  font-weight: 700;
  color: #00E599;
  margin-bottom: 8px;
}

.sub-tag::before {
  content: "";
  display: inline-block;
  width: 8px;
  height: 32px;
  background-color: #00E599;
  margin-right: 16px;
  border-radius: 4px;
}

.sub-text {
  font-size: 38px;
  line-height: 1.5;
  color: #D1D6E0;
}

.page-footnote {
  font-size: 34px;
  color: #5A6475;
  line-height: 1.5;
  margin-top: 32px;
  border-top: 1px solid #1A2233;
  padding-top: 32px;
}

.page { width: 1242px; height: 1660px; background-color: #111111; color: #FFFFFF; padding: 100px; box-sizing: border-box; font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif; display: flex; flex-direction: column; letter-spacing: 0; }

.page-header { display: flex; align-items: center; gap: 16px; font-size: 36px; color: #888888; margin-bottom: 40px; font-weight: 500; }

.page-title { font-size: 88px; font-weight: 900; line-height: 1.25; margin-bottom: 40px; color: #FFFFFF; }

.page-title p { margin: 0; }

.highlight-section { background-color: #1A1A1A; border-left: 12px solid #FF4433; padding: 32px 40px; margin-bottom: 40px; border-radius: 0 16px 16px 0; }

.highlight-value { font-size: 100px; font-weight: 900; color: #FF4433; line-height: 1.1; margin-bottom: 12px; }

.highlight-sub { font-size: 36px; color: #CCCCCC; line-height: 1.4; }

.sub-items { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 32px; }

.sub-item { padding-bottom: 32px; border-bottom: 1px solid #2A2A2A; }

.sub-item:last-child { border-bottom: none; padding-bottom: 0; }

.sub-content { line-height: 1.55; text-align: justify; }

.sub-tag { display: inline-block; background-color: #2A2A2A; color: #FF4433; font-size: 32px; font-weight: bold; padding: 4px 12px; border-radius: 6px; margin-right: 16px; position: relative; top: -2px; }

.sub-text { font-size: 38px; color: #DDDDDD; }

.footnote { margin-top: auto; font-size: 30px; color: #666666; line-height: 1.4; border-top: 1px solid #222222; padding-top: 24px; }

.page {
  width: 1242px;
  height: 1660px;
  background-color: #fcfcfc;
  box-sizing: border-box;
  padding: 100px 108px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 70px;
}

.header-icon {
  font-size: 44px;
}

.header-label {
  font-size: 38px;
  font-weight: 700;
  color: #555;
  letter-spacing: 0;
}

.title-section {
  display: flex;
  flex-direction: column;
  gap: 16px;
  margin-bottom: 80px;
}

.page-title {
  font-size: 104px;
  font-weight: 800;
  line-height: 1.15;
  color: #111;
  letter-spacing: 0;
}

.cta-content {
  display: flex;
  flex-direction: column;
  gap: 56px;
}

.cta-item {
  position: relative;
  display: flex;
  flex-direction: column;
  padding-left: 40px;
}

.cta-item::before {
  content: "";
  position: absolute;
  left: 0;
  top: 10px;
  bottom: 0;
  width: 8px;
  background-color: #111;
  border-radius: 4px;
}

.cta-item:nth-child(2)::before {
  background-color: #666;
}

.cta-item:nth-child(3)::before {
  background-color: #aaa;
}

.cta-tag {
  font-size: 38px;
  font-weight: 800;
  color: #111;
  margin-bottom: 16px;
  letter-spacing: 0;
}

.cta-text {
  font-size: 42px;
  line-height: 1.55;
  color: #333;
  letter-spacing: 0;
}
